const crypto = require('crypto');

// ============================================
// 【請再次確認金鑰是否有隱藏空格或複製錯誤】
// ============================================
const HASH_KEY = 'reBIIWJl6s7csh3eAZTzSTxDA1pW6UVh';
const HASH_IV = 'P1ayLDVHQc4HIXvC';

// 【請貼上您上一筆 Log 中出現的最新 TradeInfo HEX】
const TRADE_INFO_HEX = '';

// ============================================

console.log('--- NewebPay SHA 終極排除診斷 ---');

const calc = (str) => crypto.createHash('sha256').update(str).digest('hex').toUpperCase();

// 組合 A: 標準 2.0 (有標籤)
console.log('組合 A (標準 2.0):', calc(`HashKey=${HASH_KEY}&TradeInfo=${TRADE_INFO_HEX}&HashIV=${HASH_IV}`));

// 組合 B: MS 特規 (無標籤) -> 我們上一輪試的
console.log('組合 B (無標籤):', calc(`HashKey=${HASH_KEY}&${TRADE_INFO_HEX}&HashIV=${HASH_IV}`));

// 組合 C: 標籤在後 (極少見但存在於某些 Node 套件)
console.log('組合 C (標籤在後):', calc(`HashKey=${HASH_KEY}&${TRADE_INFO_HEX}TradeInfo=&HashIV=${HASH_IV}`));

// 組合 D: 全小寫 Hex (某些 PHP 轉 Node 會發生的問題)
console.log('組合 D (全部小寫化):', calc(`HashKey=${HASH_KEY}&TradeInfo=${TRADE_INFO_HEX.toLowerCase()}&HashIV=${HASH_IV}`));

console.log('------------------------------');
console.log('請比對瀏覽器 Network 中的 TradeSha，看看是否中了其中一個？');
